import{_ as a,o as n,c as r,ag as t}from"./chunks/framework.DXGyWiRo.js";const p="/images/uebung013.jpg",k=JSON.parse('{"title":"Übung Lektion 9","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung09.md","filePath":"lektionen/uebung09.md"}'),i={name:"lektionen/uebung09.md"};function u(s,e,l,m,h,d){return n(),r("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-9" tabindex="-1">Übung Lektion 9 <a class="header-anchor" href="#ubung-lektion-9" aria-label="Permalink to &quot;Übung Lektion 9&quot;">​</a></h1><p>A) Versuchen Sie, die möglichen Bedeutungen folgender Wörter zu bestimmen:</p><p>1. brāhmānaka ब्राह्मणक : m. einer, der einem Brahmanen nur ähnlich ist = ein schlechter Brahmane</p><p>2. mati मति : f. Meinung</p><p>3. śravaṇa श्रवण : n. Ohr</p><p>4. dhenuka m. धेनुक : m. (Koitus) in der Art einer Kuh</p><p>5. jayaka जयक : 3  siegreich</p><p>6. rakṣikā रक्षिका : f. Wächterin, Amulett</p><p>7. karṣaka कर्षक : 3 pflügend ; m. Ackerbauer</p><p>8. kleśa क्लेश : m. Qual</p><p>9. nāyikātva नायिकात्व : n. Zustand einer Geliebten</p><p>10. tantraka तन्त्रक 3 (eben) von der Webkette / dem Webstuhl kommend = neu gewebt</p><p>11. nartaka (f. nartakī) नर्तक नर्तकी : Tänzer</p><p>12. naraka नरक : m. Hölle</p><p>13. lābhaka लाभक : m. = lābha f.</p><p>14. īśvaratā ईश्वरता : f. HERR-Sein</p><p>15. dhenukā f. धेनुका = dhenu f.</p><p>16. yodhaka योधक : m. Kämpfer</p><p>17. kopa कोप : m. Zorn</p><p>18. veśaka वेशक : 3 eintretend</p><p>19. darśaka दर्शक : 3 sehend</p><p>20. kopaka कोपक : 3 jemand, der leicht zornig ist, jähzornig</p><p>B) Übersetzen Sie:</p><p>1. Aufgaben aller Zweimalgeborenen:</p><p>ijyādhyayanadānāni इज्याध्ययनदानानि</p><p>(Yājñavalkyadharmaśāstra I, 118)</p><p>Opfer, Vedastudium, Gaben geben.</p><p>2. Spezifische Aufgaben eines Brahmanen:</p><p>pravacanayājanapratigrahāḥ प्रवचनयाजनप्रतिग्रहाः</p><p>(Gautamadharmasūtra X,2)</p><p>Lehren, Opfern im Auftrag, Annahme von Gaben.</p><p>3. Spezifische Aufgaben eines Kṣatriya:</p><p>rakṣaṇaṃ sarvabhūtānām रक्षणं सर्वभूतानाम्</p><p>(sarvabhūtānām = Genetiv (Wesfall): &quot;aller Wesen&quot;)</p><p>(Gautamadharmasūtra X,7)</p><p>Hüten aller Wesen.</p><p>4. Spezifische Aufgaben eines Vaiśya:</p><p>kṛṣivāṇijyapāśupālyakusīdam कृषिवाणिज्यपाशुपाल्यकुसीदम्</p><p>(nach Gautamadharmasūtra X,49)</p><p>Ackerbau, Handel, Viehhaltung und Geldleihe.</p><p>5. Aufgaben eines Śūdra:</p><p>dvijātīnāṃ śuśrūṣā vārttā kārukuśīlavakarma ca. द्विजातीनं शुश्रूषा वार्त्त्ता कारुकुशीलवकर्म च</p><p>(nach Kauṭilīya-arthaśāstra 1.3.8.)</p><p>Erklärung:</p><p>dvijātīnām = Genetiv (Wesfall) Plural zu dvijāti (übersetzen Sie hier: &quot;gegenüber den Zweimalgeborenen&quot;)</p><p>kārukuśīlavakarma ist ein Tatpuruṣa mit einem Dvandva (kārukuśīlava) im Vorderglied. karma = Nom. sg. zu karman n. &quot;Tat, Tätigkeit, Karma&quot; zur Wurzel kṛ 8 U). Übersetzen Sie &quot;Tat / Tätigkeit der ... (Genetiv)&quot; (durch das Dvandva Bezeichneten).</p><p>Gehorsam gegenüber den Zweimalgeborenen, Tätigkeiten zum Lebensunterhalt, Tätigkeit als Handwerker bzw. wandernde Schausteller.</p><p>6. kṛṣiḥ pāśupālyaṃ vaṇijyā ca vārttā. कृषिः पाशुपाल्यं वणिज्या च वार्त्ता |</p><p>(nach Kauṭilīya-arthaśāstra 1.4.1.)</p><p>Ökonomie ist Ackerbau, Viehhaltung und Handel.</p><p><img src="'+p+'" alt=""><br> Abb.: rakṣaṇaṃ sarvabhūtānām = रक्षणं सर्वभूतानाम्<br> Dharma Raja Karthika Thirunal Rama Varma (ധര്‍മ്മ രാജ കാര്‍ത്തിക തിരുനാള്‍ രാ‍മവര്‍മ്മ), Mahārāja von Travancore (തിരുവിതാങ്കൂര്) 1758 -1798, ein Kṣatriya<br> [Bildquelle: Wikipedia, GNU FDLizenz]</p>',52)])])}const b=a(i,[["render",u]]);export{k as __pageData,b as default};
